def solve(s: str, k: int) -> str:
    result = []

    for char in s:
        if char == '*':
            if result:
                result.pop()
        elif char == '#':
            result += result[:]
        elif char == '%':
            result = result[::-1]
        else:
            result.append(char)

    if k < len(result):
        return result[k]
    else:
        return '.'
